    slug: "anansi-and-the-pot-of-wisdom",
    titleEn: "Anansi and the Pot of Wisdom",
    titleId: "Anansi dan Periuk Kebijaksanaan",
    descriptionEn: "A clever spider tries to keep all the world's wisdom for himself — and learns something wiser than he expected.",
    descriptionId: "Laba-laba cerdik berusaha menyimpan semua kebijaksanaan dunia untuk dirinya sendiri — lalu belajar sesuatu yang lebih bijak dari dugaannya.",
    categorySlug: "moral-stories",
    authorSlug: "axto-creative-team",
    coverEmoji: "🕷️",
    coverPalette: "forest",
    ageMin: 4,
